                        textTransform: "uppercase", fontFamily: fonts.mono, flexShrink: 0,
                      }}>
                        {p.priority || "medium"}
                      </span>
                      <span style={{
                        fontWeight: 600, fontSize: fontSize.sm, color: colors.text,
                        fontFamily: fonts.sans, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
                      }}>
                        {p.title}
                      </span>
