    fontSize: 11,
    color: "rgba(200,163,90,0.5)",
    letterSpacing: "0.2em",
    textTransform: "uppercase",
  },
  tabs: {
    display: "flex",
    position: "relative",
    background: "rgba(255,255,255,0.05)",
    borderRadius: 8,
    padding: 4,
    marginBottom: 24,
  },
  tab: {
    flex: 1,
    background: "transparent",
    border: "none",
    color: "rgba(255,255,255,0.45)",
    fontSize: 13,
    fontWeight: 500,
    padding: "7px 0",
    cursor: "pointer",
    borderRadius: 6,
    position: "relative",
    zIndex: 1,
    transition: "color 0.2s",
  },
  tabActive: {
    color: "#C8A35A",
  },
  tabIndicator: {
    position: "absolute",
    top: 4,
    bottom: 4,
    width: "calc(50% - 4px)",
    background: "rgba(200,163,90,0.12)",
    borderRadius: 6,
    border: "1px solid rgba(200,163,90,0.2)",
    transition: "left 0.2s cubic-bezier(0.4,0,0.2,1)",
  },
  formWrap: {},
  form: {
    display: "flex",
    flexDirection: "column",
    gap: 14,
  },
  field: {
    display: "flex",
    flexDirection: "column",
    gap: 5,
  },
  label: {
    fontSize: 12,
    color: "rgba(255,255,255,0.45)",
    letterSpacing: "0.05em",
  },
  input: {
    background: "rgba(255,255,255,0.06)",
    border: "1px solid rgba(255,255,255,0.1)",
    borderRadius: 8,
    color: "#fff",
    fontSize: 14,
    padding: "9px 12px",
    outline: "none",
    width: "100%",
    boxSizing: "border-box",
    transition: "border-color 0.15s",
  },
  error: {
    fontSize: 12,
    color: "#E57373",
    background: "rgba(229,115,115,0.08)",
    border: "1px solid rgba(229,115,115,0.2)",
    borderRadius: 6,
    padding: "7px 10px",
  },
  btn: {
    marginTop: 4,
    background: "linear-gradient(135deg, #C8A35A, #A07840)",
    border: "none",
    borderRadius: 8,
    color: "#1a1410",
    fontSize: 14,
    fontWeight: 600,
    padding: "11px",
    cursor: "pointer",
    transition: "opacity 0.15s",
    letterSpacing: "0.03em",
  },
  btnDisabled: {
    opacity: 0.5,
    cursor: "not-allowed",
  },
  footer: {
    marginTop: 20,
    textAlign: "center",
    fontSize: 12,
    color: "rgba(255,255,255,0.35)",
  },
  link: {
    background: "none",
    border: "none",
    color: "#C8A35A",
    fontSize: 12,
    cursor: "pointer",
    padding: 0,
    textDecoration: "underline",
  },
};
"}

